noncompliant:
void process(int data, int unusedParam) { // Noncompliant: unusedParam is not used
  printf("Processing: %d\n", data);
}

compliant:
void process(int data) { // Compliant: removed unused parameter
  printf("Processing: %d\n", data);
}

// Or if parameter must exist for API compatibility:
void f([[maybe_unused]] int i) {
  assert(i < 42); // In optimized mode, this assert will be removed, and "i" will be unused
}
